gap_closure_plan = {
    "id": "gap-prompt-ops-pipeline",
    "dimension": "platform_infrastructure",
    "current_level": 2,
    "target_level": 4,
    "horizon": "H2",
    "target_quarter": "2026-Q3",
    "owner": "platform-engineering-lead",
    "activities": [
        {
            "id": "act-001",
            "description": "Deploy prompt version-control system",
            "due": "2026-07-31",
            "status": "in_progress",  # not_started | in_progress | done | blocked
            "blocker": None
        },
        {
            "id": "act-002",
            "description": "Define CI gate for prompt regression",
            "due": "2026-08-15",
            "status": "not_started",
            "blocker": "act-001"  # dependency
        },
        {
            "id": "act-003",
            "description": "Integrate with golden test-set library",
            "due": "2026-08-31",
            "status": "not_started",
            "blocker": "act-002"
        },
    ],
    "leading_indicators": {
        "prompts_in_vcs": 0,         # target: 100% of production prompts
        "ci_gate_enabled": False,    # target: True
    },
    "lagging_indicators": {
        "regression_incidents_last_30d": None,  # target: 0
        "prompt_review_time_p50_hours": None,   # target: < 4h
    },
    "investment": {
        "engineering_weeks": 12,
        "tooling_cost_usd": 8000,
        "change_mgmt_weeks": 3,
    },
}

def closure_health_status(plan):
    """Returns RAG status for a closure plan."""
    activities = plan["activities"]
    done = sum(1 for a in activities if a["status"] == "done")
    blocked = sum(1 for a in activities if a["status"] == "blocked")
    total = len(activities)

    if blocked > 0:
        return "RED"
    if done / total >= 0.5:
        return "GREEN"
    # Check if on track for deadline
    return "AMBER"
